insert into public.brands (id, name, slug, country, positioning, official_url, description) values
('00000000-0000-4000-8000-000000000001', 'Doppelherz', 'doppelherz', 'Germany', '德国大众药房与商超常见补剂品牌', 'https://www.doppelherz.de/', 'Doppelherz 是德国消费者熟悉的营养补充剂品牌，产品线覆盖维生素、矿物质、心血管、眼部与日常健康支持。'),
('00000000-0000-4000-8000-000000000002', 'Orthomol', 'orthomol', 'Germany', '偏高端的德国药房营养医学品牌', 'https://www.orthomol.com/', 'Orthomol 常见于德国药房渠道，强调复合营养方案。MVP 中仅作品牌与结构演示，不构成具体疗效承诺。'),
('00000000-0000-4000-8000-000000000003', 'Mivolis', 'mivolis', 'Germany', 'dm 自有健康与补剂品牌', 'https://www.dm.de/marken/mivolis', 'Mivolis 是 dm 药妆渠道自有品牌，覆盖基础维生素、矿物质和日常健康支持产品。'),
('00000000-0000-4000-8000-000000000004', 'Abtei', 'abtei', 'Germany', '德国传统健康补充剂品牌', 'https://www.abtei.de/', 'Abtei 在德国补剂市场具有较长历史，常见产品包括维生素、矿物质、草本和日常健康支持。');
insert into public.ingredients (id, name_cn, name_en, name_de, slug, category, food_sources, summary, function_summary, warnings, evidence_level) values
('10000000-0000-4000-8000-000000000001', '镁', 'Magnesium', 'Magnesium', 'magnesium', 'mineral', '坚果、全谷物、豆类、深绿色蔬菜。', '镁是人体必需矿物质，参与肌肉、神经和能量代谢相关过程。', '与正常肌肉功能、神经系统功能和电解质平衡有关。是否需要补充应结合饮食、生活方式与个人情况。', '肾功能异常、正在使用特定药物或易腹泻人群应先咨询医生或药师；高剂量镁可能引起胃肠不适。', 'moderate'),
('10000000-0000-4000-8000-000000000002', 'Omega-3 脂肪酸', 'Omega-3', 'Omega-3-Fettsaeuren', 'omega-3', 'fatty acid', '深海鱼、亚麻籽、核桃、菜籽油。', 'Omega-3 通常指 EPA、DHA 与 ALA 等脂肪酸，饮食来源优先。', 'EPA/DHA 与心血管健康相关指标存在研究关联，但不能替代正规治疗或生活方式干预。', '正在使用抗凝药、即将手术或有出血风险者应咨询医生；注意产品氧化和来源质量。', 'moderate'),
('10000000-0000-4000-8000-000000000003', '维生素 D3', 'Vitamin D3', 'Vitamin D3', 'vitamin-d3', 'vitamin', '日照、脂肪鱼、蛋黄、强化食品。', '维生素 D 与钙磷代谢和骨骼健康相关，缺乏风险受日照与饮食影响。', '可用于支持维持正常骨骼、牙齿和肌肉功能。补充剂量宜参考检测结果和专业建议。', '避免长期超量；高钙血症、肾病或使用相关药物者应咨询医生。', 'strong'),
('10000000-0000-4000-8000-000000000004', '锌', 'Zinc', 'Zink', 'zinc', 'mineral', '牡蛎、肉类、坚果、豆类、全谷物。', '锌是必需微量元素，参与免疫、皮肤和多种酶功能。', '与正常免疫系统功能有关，但补锌不等于预防或治疗感染。', '长期高剂量可能影响铜状态；与铁、钙和某些药物同服可能影响吸收。', 'moderate'),
('10000000-0000-4000-8000-000000000005', '辅酶 Q10', 'CoQ10', 'Coenzym Q10', 'coq10', 'coenzyme', '肉类、鱼类、坚果，人体也可自行合成。', '辅酶 Q10 参与细胞能量代谢，常见于心血管与活力支持类产品。', '研究方向包括能量代谢和心血管相关人群，但证据与适用边界需要谨慎解读。', '使用华法林等抗凝药或慢性病用药者应先咨询医生。', 'limited'),
('10000000-0000-4000-8000-000000000006', '叶黄素', 'Lutein', 'Lutein', 'lutein', 'carotenoid', '菠菜、羽衣甘蓝、玉米、蛋黄。', '叶黄素是类胡萝卜素，集中于眼部黄斑区域，饮食摄入很重要。', '常用于眼部健康支持讨论，尤其与长期屏幕使用和中老年眼部营养关注相关。', '不能替代眼科检查；视力变化、眼痛或突发症状应及时就医。', 'moderate');
insert into public.products (id, brand_id, name_cn, name_original, slug, category, dosage_form, package_size, image_url, summary, warnings, is_demo) values
('20000000-0000-4000-8000-000000000001', '00000000-0000-4000-8000-000000000001', 'Doppelherz 镁片（演示）', 'Doppelherz Magnesium 400', 'doppelherz-magnesium-400-demo', 'Minerals', 'tablet', '60 tablets', null, '演示用德国镁补充剂条目，用于展示矿物质、剂量和主题关联。', '具体剂量和标签以原包装为准；肾功能异常者需先咨询专业人士。', true),
('20000000-0000-4000-8000-000000000002', '00000000-0000-4000-8000-000000000001', 'Doppelherz Omega-3 胶囊（演示）', 'Doppelherz Omega-3 1400', 'doppelherz-omega-3-demo', 'Omega-3', 'capsule', '30 capsules', null, '演示用 Omega-3 产品条目，用于展示心血管主题下的透明推荐解释。', '抗凝用药、出血风险或手术前人群应咨询医生。', true),
('20000000-0000-4000-8000-000000000003', '00000000-0000-4000-8000-000000000003', 'Mivolis 维生素 D3（演示）', 'Mivolis Vitamin D3', 'mivolis-vitamin-d3-demo', 'Vitamins', 'tablet', '100 tablets', null, '演示用维生素 D3 条目，用于骨骼健康主题和成分页面关联展示。', '避免长期超量；如已检测缺乏或患有肾病，应遵医嘱。', true),
('20000000-0000-4000-8000-000000000004', '00000000-0000-4000-8000-000000000004', 'Abtei 锌片（演示）', 'Abtei Zink', 'abtei-zinc-demo', 'Minerals', 'tablet', '42 tablets', null, '演示用锌补充剂条目，展示免疫支持主题下的边界说明。', '长期高剂量补锌可能影响铜状态，儿童与孕期人群需专业建议。', true),
('20000000-0000-4000-8000-000000000005', '00000000-0000-4000-8000-000000000002', 'Orthomol 眼部营养组合（演示）', 'Orthomol Vision', 'orthomol-vision-demo', 'Eye Health', 'capsule', '30 daily servings', null, '演示用眼部健康复合营养条目，含叶黄素等方向性成分。', '不能替代眼科检查；突发眼部症状应及时就医。', true),
('20000000-0000-4000-8000-000000000006', '00000000-0000-4000-8000-000000000001', 'Doppelherz 辅酶 Q10（演示）', 'Doppelherz Coenzym Q10', 'doppelherz-coq10-demo', 'Cell Energy', 'capsule', '30 capsules', null, '演示用辅酶 Q10 条目，适合展示有限证据与用药相互作用提示。', '慢性病用药、抗凝药使用者应先咨询医生。', true);
insert into public.product_ingredients (product_id, ingredient_id, amount, unit, serving_size, ingredient_form, daily_value_percent, note) values
('20000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000001', 400, 'mg', '1 tablet', 'mixed salts', null, '演示剂量，真实标签需核对原包装。'),
('20000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000002', 1400, 'mg fish oil', '1 capsule', 'fish oil concentrate', null, '演示条目，EPA/DHA 细分含量需按标签录入。'),
('20000000-0000-4000-8000-000000000003', '10000000-0000-4000-8000-000000000003', 25, 'ug', '1 tablet', 'cholecalciferol', 500, '演示剂量，需结合标签与当地参考摄入标准。'),
('20000000-0000-4000-8000-000000000004', '10000000-0000-4000-8000-000000000004', 10, 'mg', '1 tablet', 'zinc gluconate', 100, '演示剂量。'),
('20000000-0000-4000-8000-000000000005', '10000000-0000-4000-8000-000000000006', 10, 'mg', '1 daily serving', 'lutein', null, '复合产品演示字段。'),
