insert into public.health_topics (id, title, slug, summary, lifestyle_advice, supplement_notes, warning_notes, medical_boundary) values
('30000000-0000-4000-8000-000000000001', '睡眠', 'sleep', '关注睡眠习惯、压力管理、咖啡因使用和可能相关的营养因素。', '优先建立固定作息、晨间光照、减少晚间酒精与屏幕刺激，并排查压力与睡眠环境问题。', '补剂只能作为辅助讨论，若长期失眠、打鼾憋醒或白天嗜睡，应先寻求专业评估。', '不要将补剂作为镇静药替代品；孕期、慢病或用药人群需咨询医生。', '本页不诊断失眠症或睡眠障碍。'),
('30000000-0000-4000-8000-000000000002', '心血管健康', 'cardiovascular-health', '从饮食、运动、体重管理、血压血脂监测和相关营养因素理解心血管支持。', '优先控制吸烟、运动不足、高盐饮食和体重等可改变因素，并按需进行体检。', 'Omega-3、辅酶 Q10 等成分可作为营养讨论入口，但不能替代降压、降脂或抗凝治疗。', '胸痛、呼吸困难、突发不适等情况应立即就医。', '本页不评估心血管疾病风险，不调整处方药。'),
('30000000-0000-4000-8000-000000000003', '眼部健康', 'eye-health', '围绕屏幕使用、户外活动、眼科检查和黄斑相关营养因素建立眼部健康认知。', '保持规律眼科检查，控制连续近距离用眼时间，增加户外活动并关注基础代谢健康。', '叶黄素等成分可作为眼部营养支持讨论，但不能替代眼科诊断或治疗。', '突发视力下降、眼痛、闪光感或视野缺损需及时就医。', '本页不判断眼病类型，不替代眼科检查。'),
('30000000-0000-4000-8000-000000000004', '女性健康', 'women-health', '关注不同生命阶段的营养、睡眠、运动、铁和维生素 D 等基础因素。', '优先保证均衡饮食、力量训练、睡眠、压力管理和定期体检。', '补剂选择应结合年龄、饮食、经期、孕备孕状态和检测结果。', '孕期、哺乳期、备孕或有妇科症状时，应先咨询医生。', '本页不处理妇科诊断或激素治疗建议。'),
('30000000-0000-4000-8000-000000000005', '骨骼健康', 'bone-health', '从日照、蛋白质、负重运动、钙和维生素 D 状态理解骨骼长期管理。', '优先进行规律负重运动、足量蛋白质摄入、合理日照和跌倒风险管理。', '维生素 D3 和矿物质补充需结合饮食、检测结果和年龄风险。', '骨折、骨痛或骨质疏松风险高的人群应接受专业评估。', '本页不诊断骨质疏松，不替代骨密度检查。'),
('30000000-0000-4000-8000-000000000006', '免疫支持', 'immune-support', '以睡眠、营养、运动和疫苗等基础措施为先，理解锌和维生素 D 等营养因素。', '优先保证睡眠、均衡饮食、适量运动、洗手和必要疫苗接种。', '锌和维生素 D 可作为营养状态支持，不应被理解为预防或治疗感染。', '持续发热、严重感染症状或免疫系统疾病应就医。', '本页不诊断感染，不替代疫苗或药物治疗。');
insert into public.topic_ingredients (topic_id, ingredient_id, relevance_level, evidence_level, explanation, caution_note) values
('30000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000001', 'medium', 'limited', '镁与神经和肌肉功能相关，睡眠主题中常作为压力、肌肉紧张和饮食不足的营养因素讨论。', '长期睡眠问题应先评估行为、压力、呼吸和疾病因素。'),
('30000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000002', 'high', 'moderate', 'EPA/DHA 与心血管相关指标存在研究关联，常作为鱼类摄入不足时的营养讨论方向。', '抗凝药、出血风险或手术前人群需先咨询医生。'),
('30000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000005', 'medium', 'limited', '辅酶 Q10 参与能量代谢，是部分心血管营养支持产品的常见成分，但证据边界需谨慎。', '不能替代处方治疗，慢病用药者需咨询医生。'),
('30000000-0000-4000-8000-000000000003', '10000000-0000-4000-8000-000000000006', 'high', 'moderate', '叶黄素集中于黄斑区域，常用于眼部营养和长期屏幕使用人群的营养讨论。', '眼部症状应优先做眼科检查。'),
('30000000-0000-4000-8000-000000000004', '10000000-0000-4000-8000-000000000003', 'medium', 'moderate', '维生素 D 状态与骨骼、肌肉和一般营养管理相关，女性不同阶段可能需要关注。', '孕备孕、哺乳或高剂量补充需专业建议。'),
('30000000-0000-4000-8000-000000000005', '10000000-0000-4000-8000-000000000003', 'high', 'strong', '维生素 D 与钙磷代谢和正常骨骼功能关系明确，是骨骼健康主题中的基础营养因素。', '补充剂量应结合日照、饮食、检测结果和个体风险。'),
('30000000-0000-4000-8000-000000000005', '10000000-0000-4000-8000-000000000001', 'medium', 'limited', '镁参与矿物质代谢与肌肉功能，可作为骨骼健康生活方式之外的辅助营养因素。', '不要用矿物质补充替代骨质疏松评估。'),
('30000000-0000-4000-8000-000000000006', '10000000-0000-4000-8000-000000000004', 'high', 'moderate', '锌与正常免疫功能有关，饮食不足或特殊阶段可作为营养状态讨论。', '补锌不等于治疗感染，避免长期高剂量。'),
('30000000-0000-4000-8000-000000000006', '10000000-0000-4000-8000-000000000003', 'medium', 'moderate', '维生素 D 与免疫功能存在研究关联，但应以纠正缺乏和维持正常状态为目标。', '不应将维生素 D 作为感染预防或治疗承诺。');
insert into public.topic_products (topic_id, product_id, relevance_level, display_order, recommendation_note, caution_note) values
('30000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000001', 'medium', 1, '该演示产品含镁，因此出现在睡眠主题的营养因素链路中。', '睡眠问题优先处理作息、压力、咖啡因和睡眠环境。'),
('30000000-0000-4000-8000-000000000002', '20000000-0000-4000-8000-000000000002', 'high', 1, '该演示产品含 Omega-3，与心血管健康主题的相关成分匹配。', '正在使用抗凝药或有出血风险者需先咨询医生。'),
('30000000-0000-4000-8000-000000000002', '20000000-0000-4000-8000-000000000006', 'medium', 2, '该演示产品含辅酶 Q10，可用于展示有限证据下的营养支持信息。', '不能替代心血管疾病治疗或处方药管理。'),
('30000000-0000-4000-8000-000000000003', '20000000-0000-4000-8000-000000000005', 'high', 1, '该演示产品含叶黄素，匹配眼部健康主题的关键营养因素。', '眼部症状优先就医，补剂不替代眼科检查。'),
('30000000-0000-4000-8000-000000000005', '20000000-0000-4000-8000-000000000003', 'high', 1, '该演示产品含维生素 D3，与骨骼健康主题的基础营养因素相关。', '避免长期超量，必要时通过检测确认状态。'),
('30000000-0000-4000-8000-000000000006', '20000000-0000-4000-8000-000000000004', 'high', 1, '该演示产品含锌，与免疫支持主题的相关营养因素匹配。', '免疫支持首先依赖睡眠、饮食、运动和疫苗等基础措施。');
insert into public.ingredient_interactions (ingredient_id, interaction_target, target_type, interaction_level, description, recommendation) values
('10000000-0000-4000-8000-000000000002', 'Anticoagulants', 'drug', 'medium', 'Omega-3 与抗凝或抗血小板用药并用时应关注出血风险。', '使用相关药物者在补充前咨询医生或药师。'),
('10000000-0000-4000-8000-000000000003', 'Hypercalcemia', 'condition', 'high', '高钙血症或相关肾脏问题人群不宜自行高剂量补充维生素 D。', '应根据检测结果和医生建议决定剂量。'),
('10000000-0000-4000-8000-000000000004', 'Iron', 'ingredient', 'low', '锌、铁、钙等矿物质同服可能相互影响吸收。', '如需多种矿物质补充，可错开服用并参考专业建议。');
